defmodule WebhookProxy.Controllers.HomeController do
  use Phoenix.Controller

  action_fallback(WebhookProxy.FallbackController)

  def fetch_content(conn, %{"url" => url}) do
    response = HTTPoison.get!(url)
    render(conn, "show.json", content: response.body)
  end
end